CREATE TABLE "Sale" ("id" TEXT NOT NULL PRIMARY KEY,"leadId" TEXT NOT NULL,"productId" TEXT NOT NULL,"planId" TEXT NOT NULL,"amountCents" INTEGER NOT NULL,"status" TEXT NOT NULL DEFAULT 'AWAITING_PAYMENT',"soldAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,"notes" TEXT,CONSTRAINT "Sale_leadId_fkey" FOREIGN KEY ("leadId") REFERENCES "Lead"("id"),CONSTRAINT "Sale_productId_fkey" FOREIGN KEY ("productId") REFERENCES "Product"("id"),CONSTRAINT "Sale_planId_fkey" FOREIGN KEY ("planId") REFERENCES "Plan"("id"));
CREATE TABLE "Subscription" ("id" TEXT NOT NULL PRIMARY KEY,"saleId" TEXT NOT NULL,"status" TEXT NOT NULL DEFAULT 'AWAITING_ACTIVATION',"currentCents" INTEGER NOT NULL,"startedAt" DATETIME,"nextBillingAt" DATETIME,CONSTRAINT "Subscription_saleId_fkey" FOREIGN KEY ("saleId") REFERENCES "Sale"("id") ON DELETE CASCADE);
CREATE TABLE "Payment" ("id" TEXT NOT NULL PRIMARY KEY,"saleId" TEXT NOT NULL,"subscriptionId" TEXT,"amountCents" INTEGER NOT NULL,"paidAt" DATETIME NOT NULL,"isFirst" BOOLEAN NOT NULL DEFAULT false,CONSTRAINT "Payment_saleId_fkey" FOREIGN KEY ("saleId") REFERENCES "Sale"("id") ON DELETE CASCADE,CONSTRAINT "Payment_subscriptionId_fkey" FOREIGN KEY ("subscriptionId") REFERENCES "Subscription"("id") ON DELETE SET NULL);
CREATE UNIQUE INDEX "Subscription_saleId_key" ON "Subscription"("saleId");
